using BgCommon.Localization;namespace BgControls.Windows.Controls;/// <summary>/// 自定义工具提示控件，通过内部 Popup 实现弹出显示逻辑./// </summary>public class RadToolTip : ContentControl{    /// <summary>    /// 标识 <see cref="HorizontalOffset"/> 依赖属性.    /// </summary>    public static readonly DependencyProperty HorizontalOffsetProperty =        DependencyProperty.Register("HorizontalOffset", typeof(double), typeof(RadToolTip), new FrameworkPropertyMetadata(0.0));    /// <summary>    /// 标识 <see cref="IsOpen"/> 依赖属性.    /// </summary>    public static readonly DependencyProperty IsOpenProperty =        DependencyProperty.Register("IsOpen", typeof(bool), typeof(RadToolTip), new PropertyMetadata(OnIsOpenChanged));    /// <summary>    /// 标识 <see cref="StaysOpen"/> 依赖属性.    /// </summary>    public static readonly DependencyProperty StaysOpenProperty =        DependencyProperty.Register("StaysOpen", typeof(bool), typeof(RadToolTip), new FrameworkPropertyMetadata(true));    /// <summary>    /// 标识 <see cref="Placement"/> 依赖属性.    /// </summary>    public static readonly DependencyProperty PlacementProperty =        DependencyProperty.Register("Placement", typeof(System.Windows.Controls.Primitives.PlacementMode), typeof(RadToolTip), new PropertyMetadata(System.Windows.Controls.Primitives.PlacementMode.Mouse));    /// <summary>    /// 标识 <see cref="PlacementRectangle"/> 依赖属性.    /// </summary>    public static readonly DependencyProperty PlacementRectangleProperty =        DependencyProperty.RegisterAttached("PlacementRectangle", typeof(Rect), typeof(RadToolTip), new PropertyMetadata(Rect.Empty));    /// <summary>    /// 标识 <see cref="PlacementTarget"/> 依赖属性.    /// </summary>    public static readonly DependencyProperty PlacementTargetProperty =        DependencyProperty.Register("PlacementTarget", typeof(UIElement), typeof(RadToolTip), new PropertyMetadata(null));    /// <summary>    /// 标识 <see cref="VerticalOffset"/> 依赖属性.    /// </summary>    public static readonly DependencyProperty VerticalOffsetProperty =        DependencyProperty.Register("VerticalOffset", typeof(double), typeof(RadToolTip), new PropertyMetadata(0.0));    /// <summary>    /// 标识内部使用的 PlacementTargetInternal 依赖属性.    /// </summary>    private static readonly DependencyProperty PlacementTargetInternalProperty =        DependencyProperty.Register("PlacementTargetInternal", typeof(UIElement), typeof(RadToolTip), null);    static RadToolTip()    {        DefaultStyleKeyProperty.OverrideMetadata(typeof(RadToolTip), new FrameworkPropertyMetadata(typeof(RadToolTip)));    }    /// <summary>    /// 承载工具提示内容的根弹出窗口.    /// </summary>    private Popup? rootPopup;    /// <summary>    /// Initializes a new instance of the <see cref="RadToolTip"/> class.    /// </summary>    public RadToolTip()    {        // 订阅加载和卸载事件以管理 Popup 资源.        this.Unloaded += this.OnRadToolTipUnloaded;    }    /// <summary>    /// Gets or sets 工具提示相对于目标位置的水平偏移量.    /// </summary>    public double HorizontalOffset    {        get { return (double)this.GetValue(HorizontalOffsetProperty); }        set { this.SetValue(HorizontalOffsetProperty, value); }    }    /// <summary>    /// Gets or sets a value indicating whether 工具提示是否处于打开状态.    /// </summary>    public bool IsOpen    {        get { return (bool)this.GetValue(IsOpenProperty); }        set { this.SetValue(IsOpenProperty, value); }    }    /// <summary>    /// Gets or sets a value indicating whether 工具提示在失去焦点时是否保持打开状态.    /// </summary>    public bool StaysOpen    {        get { return (bool)this.GetValue(StaysOpenProperty); }        set { this.SetValue(StaysOpenProperty, value); }    }    /// <summary>    /// Gets or sets 工具提示相对于目标元素的放置模式.    /// </summary>    public System.Windows.Controls.Primitives.PlacementMode Placement    {        get { return (System.Windows.Controls.Primitives.PlacementMode)this.GetValue(PlacementProperty); }        set { this.SetValue(PlacementProperty, value); }    }    /// <summary>    /// Gets or sets 用于定位工具提示的矩形区域.    /// </summary>    public Rect PlacementRectangle    {        get { return (Rect)this.GetValue(PlacementRectangleProperty); }        set { this.SetValue(PlacementRectangleProperty, value); }    }    /// <summary>    /// Gets or sets 工具提示打开时相对于的 UI 元素.    /// </summary>    public UIElement? PlacementTarget    {        get { return (UIElement?)this.GetValue(PlacementTargetProperty); }        set { this.SetValue(PlacementTargetProperty, value); }    }    /// <summary>    /// Gets or sets 工具提示相对于目标位置的垂直偏移量.    /// </summary>    public double VerticalOffset    {        get { return (double)this.GetValue(VerticalOffsetProperty); }        set { this.SetValue(VerticalOffsetProperty, value); }    }    /// <summary>    /// Gets or sets 内部使用的实际放置目标元素.    /// </summary>    internal UIElement? PlacementTargetInternal    {        get { return (UIElement?)this.GetValue(PlacementTargetInternalProperty); }        set { this.SetValue(PlacementTargetInternalProperty, value); }    }    /// <summary>    /// Gets or sets 工具提示的所有者元素.    /// </summary>    internal FrameworkElement? Owner { get; set; }    /// <summary>    /// Gets or sets 触发工具提示时的鼠标位置坐标.    /// </summary>    internal Point MousePosition { get; set; }    /// <summary>    /// Gets a value indicating whether 控件模板是否已成功应用.    /// </summary>    internal bool IsTemplateApplied { get; private set; }    /// <summary>    /// Gets or sets 工具提示的根弹出窗口实例.    /// </summary>    internal Popup RootPopup    {        get        {            this.CreateRootPopupIfNeeded();            return this.rootPopup;        }        private set        {            if (this.rootPopup != value)            {                this.rootPopup = value;            }        }    }    /// <summary>    /// 在控件初始化完成时触发.    /// </summary>    /// <param name="e">事件参数.</param>    protected override void OnInitialized(EventArgs e)    {        base.OnInitialized(e);    }    /// <summary>    /// 获取当前生效的放置目标，如果未显式设置则返回所有者元素.    /// </summary>    /// <returns>实际使用的 UI 元素目标.</returns>    internal UIElement GetActualPlacementTarget()    {        return this.PlacementTarget ?? this.Owner;    }    /// <summary>    /// 清理根弹出窗口关联的资源.    /// </summary>    internal void CleanUpRootPopup()    {        if (this.rootPopup != null)        {            this.rootPopup.IsOpen = false;            this.rootPopup.DataContext = null;            this.rootPopup.Child = null;            System.Windows.Data.BindingOperations.ClearAllBindings(this.rootPopup);            this.rootPopup = null;        }    }    /// <summary>    /// 执行弹出窗口的打开逻辑.    /// </summary>    private void OpenPopup()    {        this.CreateRootPopupIfNeeded();    }    /// <summary>    /// 执行弹出窗口的关闭逻辑.    /// </summary>    private void ClosePopup()    {        // 1. 确保内部的放置目标引用被清除，防止在关闭期间持有所属元素的强引用.        this.PlacementTargetInternal = null;        // 2. 如果根弹出窗口存在，确保其状态同步（虽然双向绑定通常能处理，但此处手动确保安全性）.        if (this.rootPopup != null)        {            this.rootPopup.IsOpen = false;        }    }    /// <summary>    /// 必要时创建根弹出窗口并同步数据上下文.    /// </summary>    private void CreateRootPopupIfNeeded()    {        this.PlacementTargetInternal = this.GetActualPlacementTarget();        if (this.rootPopup == null)        {            this.rootPopup = new Popup();            CreateRootPopup(this.rootPopup, this);        }        if (this.Owner != null)        {            // 将所有者的 DataContext 传递给弹出窗口.            this.rootPopup.DataContext = this.Owner.DataContext;        }    }    /// <summary>    /// 处理控件卸载事件，执行资源清理以防止内存泄漏.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数接口.</param>    private void OnRadToolTipUnloaded(object sender, RoutedEventArgs e)    {        this.CleanUpRootPopup();    }    /// <summary>    /// 从指定的元素获取 <see cref="PlacementRectangleProperty"/> 附加属性值.    /// </summary>    /// <param name="element">要从中读取属性值的对象.</param>    /// <returns>放置矩形区域.</returns>    public static Rect GetPlacementRectangle(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (Rect)element.GetValue(PlacementRectangleProperty);    }    /// <summary>    /// 将 <see cref="PlacementRectangleProperty"/> 附加属性值设置到指定的元素上.    /// </summary>    /// <param name="element">要设置属性值的对象.</param>    /// <param name="value">要设置的放置矩形区域.</param>    public static void SetPlacementRectangle(DependencyObject element, Rect value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(PlacementRectangleProperty, value);    }    /// <summary>    /// 当 IsOpen 属性发生更改时的回调处理.    /// </summary>    /// <param name="sender">属性所有者.</param>    /// <param name="e">更改参数.</param>    private static void OnIsOpenChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        RadToolTip radToolTip = (RadToolTip)sender;        if ((bool)e.NewValue)        {            radToolTip.OpenPopup();        }        else        {            radToolTip.ClosePopup();        }    }    /// <summary>    /// 静态辅助方法：配置弹出窗口与子元素之间的绑定关系.    /// </summary>    /// <param name="popup">目标 Popup 实例.</param>    /// <param name="child">要承载的工具提示内容元素.</param>    private static void CreateRootPopup(Popup popup, FrameworkElement child)    {        // 验证参数非空.        ArgumentNullException.ThrowIfNull(popup, nameof(popup));        ArgumentNullException.ThrowIfNull(child, nameof(child));        // 检查元素是否已存在于逻辑树或视觉树中.        object? visualParent = child.Parent;        if (visualParent != null)        {            throw new InvalidOperationException(LocalizationProviderFactory.GetString("ToolTipHasLogicalOrVisualParent", child, visualParent));        }        visualParent = VisualTreeHelper.GetParent(child);        if (visualParent != null)        {            throw new InvalidOperationException(LocalizationProviderFactory.GetString("ToolTipHasLogicalOrVisualParent", child, visualParent));        }        // 设置弹出窗口内容.        popup.Child = child;        popup.AllowsTransparency = true;        // 绑定实际放置目标属性.        popup.SetBinding(Popup.PlacementTargetProperty, new Binding()        {            Path = new PropertyPath(PlacementTargetInternalProperty),            Mode = BindingMode.OneWay,            Source = child,        });        // 绑定垂直偏移量.        popup.SetBinding(Popup.VerticalOffsetProperty, new Binding()        {            Path = new PropertyPath(VerticalOffsetProperty),            Mode = BindingMode.OneWay,            Source = child,        });        // 绑定水平偏移量.        popup.SetBinding(Popup.HorizontalOffsetProperty, new Binding()        {            Path = new PropertyPath(HorizontalOffsetProperty),            Mode = BindingMode.OneWay,            Source = child,        });        // 绑定放置矩形区域.        popup.SetBinding(Popup.PlacementRectangleProperty, new Binding()        {            Path = new PropertyPath(PlacementRectangleProperty),            Mode = BindingMode.OneWay,            Source = child,        });        // 绑定放置模式属性.        popup.SetBinding(Popup.PlacementProperty, new Binding()        {            Path = new PropertyPath(PlacementProperty),            Mode = BindingMode.OneWay,            Source = child,        });        // 双向绑定打开状态，确保弹出窗口与控件状态同步.        popup.SetBinding(Popup.IsOpenProperty, new Binding()        {            Path = new PropertyPath(IsOpenProperty),            Mode = BindingMode.TwoWay,            Source = child,        });        // 绑定保持打开状态属性.        popup.SetBinding(Popup.StaysOpenProperty, new Binding()        {            Path = new PropertyPath(StaysOpenProperty),            Mode = BindingMode.TwoWay,            Source = child,        });    }}